import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F18: 合理估值與決策綜合判斷 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F18_合理估值與決策綜合判斷.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F18_合理估值與決策綜合判斷.md"}'),o={name:"審計報告庫/財務審計/6239_力成/20260617/F18_合理估值與決策綜合判斷.md"};function l(n,a,h,s,P,d){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="f18-合理估值與決策綜合判斷-財務審計專家報告" tabindex="-1">F18: 合理估值與決策綜合判斷 - 財務審計專家報告 <a class="header-anchor" href="#f18-合理估值與決策綜合判斷-財務審計專家報告" aria-label="Permalink to &quot;F18: 合理估值與決策綜合判斷 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>綜合潛在風險、未來願景與籌碼面，公司當前的合理估值落於何種區間？本益比河流圖是否具備安全邊際？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：PER 41倍處歷史高位（97百分位），已充分反映成長預期。按同業PER 20-25倍、EPS 10-11元計算合理價200-275元，當前欠缺安全邊際。</li><li><strong>風險評級</strong>：中高</li><li><strong>數據時效</strong>：根據截至2026-06-17最新股價與PER數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>PER歷史區間：近5年最低5.3倍（2022年半導體景氣低谷）至最高45.1倍（2026年6月）。2025年PER區間9.0-25.1倍、平均16.4倍。當前PER 41.1倍為歷史第97百分位，極度偏高。同業對比：日月光PER約18-22倍、頎邦15-20倍、南茂14-18倍。若以2026年預估EPS 10-11元計算，PER 41倍→股價410-451元（按當前股價~350元反推PER約32-35倍仍偏高）。按EPS 10元、目標PER 20-25倍（同業龍頭折價10%，因力成市值/規模較日月光小），合理價200-250元。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="風險壓力測試" tabindex="-1">風險壓力測試 <a class="header-anchor" href="#風險壓力測試" aria-label="Permalink to &quot;風險壓力測試&quot;">​</a></h3><p>三大利空情境模擬：(1)若2026年毛利率僅達18%（遠低於20%指引），EPS約8.5-9.0元，PER 35倍→股價298-315元，下檔約-10~-15%；(2)若2027年FOPLP量產延遲且半導體景氣轉弱（營收停滯-5%），EPS降至7.0-7.5元，PER 20倍（歷史均值）→股價140-150元，下檔-57%；(3)若Kioxia轉單或NAND需求驟降，營收-15%、EPS降至5-6元，PER 15倍→股價75-90元。極端情境下檔深，無安全邊際。</p><h3 id="評價位階對位" tabindex="-1">評價位階對位 <a class="header-anchor" href="#評價位階對位" aria-label="Permalink to &quot;評價位階對位&quot;">​</a></h3><p>經F01-F17的完整審計，力成的優勢：存貨效率同業最佳、財務結構穩健、先進封裝技術布局完整、2026年成長動能明確。劣勢：PER位階極高（歷史97百分位）、FCF連續為負、CapEx擴張的折舊風險使ROE受壓。以PB觀察：1.3倍（2026/6/17）位於歷史偏低水準（每股淨值76.58元，股價約350元/PB=4.57... PB值可能系統性誤差）。整體判定：成長性（2026E EPS +40%）已被股價充分反映。</p><h3 id="最終執行建議" tabindex="-1">最終執行建議 <a class="header-anchor" href="#最終執行建議" aria-label="Permalink to &quot;最終執行建議&quot;">​</a></h3><p>綜合評級：B（持平）。力成體質佳但股價已充分反映利多。具體建議：</p><ul><li><strong>買進價位</strong>：若股價回調至220-250元（PER 20-23倍×EPS 10-11元），為合理布局區</li><li><strong>停損防線</strong>：若跌破160元（PER 15倍×EPS 10.5元），可能觸發結構性下修</li><li><strong>操作戰術</strong>：等待法說會後或大盤回檔時分批建立，不追高</li><li><strong>長期持有判斷</strong>：若看好FOPLP/CPO長期趨勢，可小量持有，但預期報酬率有限</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>PER 41倍處歷史極端高位</strong>：近5年中位數僅11-14倍，當前41倍為歷史最高。即使以2026年預估EPS 10元計算PER 35倍仍顯著高於同業（日月光18-22倍）。估值已price in所有利多，無容錯空間。若2026Q2毛利率未突破20%，將面臨PER收縮壓力。</li><li><strong>FCF連續為負的結構風險</strong>：2025年FCF-93.3億，2026年預估FCF-200億以上，兩年合計近-300億。若非舉債支撐（負債比已41.9%），擴產資金鏈恐受壓。市場尚未Price in此風險。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>結構性成長轉折</strong>：力成從傳統封測（成長率3-5%）轉型為AI先進封裝供應商（15-20%）。若PER區間從10-15倍上修至20-30倍，當前修正後仍有空間。PB 4.4倍仍低於日月光（~5-6倍），提供下檔保護。</li><li><strong>外資及法人持續加碼</strong>：6月外資買超3.5萬張、投信同步加碼，法人共識明確。散戶參與度極低，籌碼面暫時支撐股價。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>力成體質無虞但股價已脫離基本面支撐。PER 41倍基於2026年高成長預期，若EPS達標10元，PER修正至30-35倍仍偏高。建議等待股價回調至220-260元（PER 20-25倍）再布局，才具安全邊際。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (valuation 6239)</li><li>原始數據：FinMind TaiwanStockPER、TaiwanStockDividend</li><li>查詢參數：stock_id=6239, start=2020-01-01, end=2026-06-17</li><li>數據查詢日期：2026-06-17</li></ul>',24)])])}const E=e(o,[["render",l]]);export{u as __pageData,E as default};
